export const PHASE9_EPISTEMIC_CORE_SQL = "PRAGMA foreign_keys = ON;\n\nCREATE TABLE IF NOT EXISTS claims (\n  id TEXT PRIMARY KEY,\n  contribution_id TEXT NOT NULL REFERENCES contributions(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  topic_id TEXT NOT NULL REFERENCES topics(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  domain_id TEXT NOT NULL REFERENCES domains(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  being_id TEXT NOT NULL REFERENCES beings(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  ordinal INTEGER NOT NULL,\n  body TEXT NOT NULL,\n  normalized_body TEXT,\n  verifiability TEXT NOT NULL DEFAULT 'unclassified',\n  status TEXT NOT NULL DEFAULT 'extracted',\n  extraction_version TEXT,\n  metadata_json TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(contribution_id, ordinal)\n);\n\nCREATE TABLE IF NOT EXISTS claim_relations (\n  id TEXT PRIMARY KEY,\n  domain_id TEXT NOT NULL REFERENCES domains(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  source_claim_id TEXT NOT NULL REFERENCES claims(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  target_claim_id TEXT NOT NULL REFERENCES claims(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  relation_kind TEXT NOT NULL CHECK (relation_kind IN ('support', 'contradiction', 'refinement', 'supersession')),\n  confidence REAL NOT NULL DEFAULT 0,\n  explanation TEXT,\n  metadata_json TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  CHECK (source_claim_id <> target_claim_id),\n  UNIQUE(source_claim_id, target_claim_id, relation_kind)\n);\n\nCREATE TABLE IF NOT EXISTS claim_resolutions (\n  id TEXT PRIMARY KEY,\n  claim_id TEXT NOT NULL UNIQUE REFERENCES claims(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  domain_id TEXT NOT NULL REFERENCES domains(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  status TEXT NOT NULL DEFAULT 'unresolved' CHECK (status IN ('unresolved', 'contested', 'supported', 'refuted', 'mixed')),\n  confidence REAL NOT NULL DEFAULT 0,\n  signal_summary_json TEXT,\n  resolved_at TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TABLE IF NOT EXISTS claim_resolution_evidence (\n  id TEXT PRIMARY KEY,\n  claim_id TEXT NOT NULL REFERENCES claims(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  contribution_id TEXT NOT NULL REFERENCES contributions(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  relation_id TEXT REFERENCES claim_relations(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  evidence_kind TEXT NOT NULL DEFAULT 'support' CHECK (evidence_kind IN ('support', 'challenge', 'context', 'correction')),\n  excerpt TEXT,\n  weight REAL NOT NULL DEFAULT 0,\n  metadata_json TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(claim_id, contribution_id, evidence_kind)\n);\n\nCREATE TABLE IF NOT EXISTS epistemic_reliability (\n  id TEXT PRIMARY KEY,\n  domain_id TEXT NOT NULL REFERENCES domains(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  being_id TEXT NOT NULL REFERENCES beings(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  reliability_score REAL NOT NULL DEFAULT 0,\n  confidence_score REAL NOT NULL DEFAULT 0,\n  supported_claim_count INTEGER NOT NULL DEFAULT 0,\n  contested_claim_count INTEGER NOT NULL DEFAULT 0,\n  refuted_claim_count INTEGER NOT NULL DEFAULT 0,\n  correction_count INTEGER NOT NULL DEFAULT 0,\n  last_evaluated_at TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(domain_id, being_id)\n);\n\nCREATE INDEX IF NOT EXISTS idx_claims_topic_ordinal\n  ON claims(topic_id, ordinal);\n\nCREATE INDEX IF NOT EXISTS idx_claims_domain_status\n  ON claims(domain_id, status, verifiability);\n\nCREATE INDEX IF NOT EXISTS idx_claim_relations_source_kind\n  ON claim_relations(source_claim_id, relation_kind);\n\nCREATE INDEX IF NOT EXISTS idx_claim_relations_target_kind\n  ON claim_relations(target_claim_id, relation_kind);\n\nCREATE INDEX IF NOT EXISTS idx_claim_resolutions_domain_status\n  ON claim_resolutions(domain_id, status, confidence DESC);\n\nCREATE INDEX IF NOT EXISTS idx_claim_resolution_evidence_claim_kind\n  ON claim_resolution_evidence(claim_id, evidence_kind, weight DESC);\n\nCREATE INDEX IF NOT EXISTS idx_epistemic_reliability_domain\n  ON epistemic_reliability(domain_id, reliability_score DESC, confidence_score DESC);\n\nCREATE TRIGGER IF NOT EXISTS trg_claims_updated_at\nAFTER UPDATE ON claims\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE claims SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n\nCREATE TRIGGER IF NOT EXISTS trg_claim_relations_updated_at\nAFTER UPDATE ON claim_relations\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE claim_relations SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n\nCREATE TRIGGER IF NOT EXISTS trg_claim_resolutions_updated_at\nAFTER UPDATE ON claim_resolutions\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE claim_resolutions SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n\nCREATE TRIGGER IF NOT EXISTS trg_claim_resolution_evidence_updated_at\nAFTER UPDATE ON claim_resolution_evidence\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE claim_resolution_evidence SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n\nCREATE TRIGGER IF NOT EXISTS trg_epistemic_reliability_updated_at\nAFTER UPDATE ON epistemic_reliability\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE epistemic_reliability SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n";
export const PHASE10_TOPIC_FORMATS_SQL = "PRAGMA foreign_keys = ON;\n\nALTER TABLE topics ADD COLUMN topic_format TEXT NOT NULL DEFAULT 'scheduled_research';\n\nUPDATE topics\nSET topic_format = CASE\n  WHEN cadence_family = 'scheduled' THEN 'scheduled_research'\n  ELSE 'rolling_research'\nEND;\n\nCREATE INDEX IF NOT EXISTS idx_topics_format_status\n  ON topics(topic_format, status, updated_at DESC);\n";
export const PHASE11_ADAPTIVE_SCORING_SQL = "ALTER TABLE topics ADD COLUMN change_sequence INTEGER NOT NULL DEFAULT 0;\nALTER TABLE topics ADD COLUMN active_participant_count INTEGER NOT NULL DEFAULT 0;\n";
export const PHASE12_PLATFORM_ANALYTICS_SQL = "PRAGMA foreign_keys = ON;\n\nCREATE TABLE IF NOT EXISTS platform_daily_rollups (\n  id TEXT PRIMARY KEY,\n  rollup_date TEXT NOT NULL UNIQUE,\n  topics_created_count INTEGER NOT NULL DEFAULT 0,\n  contributions_created_count INTEGER NOT NULL DEFAULT 0,\n  verdicts_created_count INTEGER NOT NULL DEFAULT 0,\n  active_topics INTEGER NOT NULL DEFAULT 0,\n  active_beings INTEGER NOT NULL DEFAULT 0,\n  active_agents INTEGER NOT NULL DEFAULT 0,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\nCREATE TRIGGER IF NOT EXISTS trg_platform_daily_rollups_updated_at\nAFTER UPDATE ON platform_daily_rollups\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE platform_daily_rollups SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n";
export const PHASE13_TOPIC_VIEW_REPUTATION_HISTORY_VOTE_TIMING_SQL = "PRAGMA foreign_keys = ON;\n\nALTER TABLE topics ADD COLUMN view_count INTEGER NOT NULL DEFAULT 0;\n\nCREATE TABLE IF NOT EXISTS domain_reputation_history (\n  id TEXT PRIMARY KEY,\n  domain_id TEXT NOT NULL REFERENCES domains(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  being_id TEXT NOT NULL REFERENCES beings(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  average_score REAL NOT NULL,\n  consistency_score REAL NOT NULL,\n  decayed_score REAL NOT NULL,\n  sample_count INTEGER NOT NULL,\n  recorded_at TEXT NOT NULL DEFAULT (strftime('%Y-%m-%dT%H:%M:%SZ','now'))\n);\n\nCREATE INDEX IF NOT EXISTS idx_domain_reputation_history_domain_being_recorded\n  ON domain_reputation_history(domain_id, being_id, recorded_at DESC);\n\nALTER TABLE votes ADD COLUMN vote_position_pct REAL;\nALTER TABLE votes ADD COLUMN round_elapsed_pct REAL;\n";
export const PHASE14_TOPIC_MEMBER_DROP_TRACKING_SQL = "PRAGMA foreign_keys = ON;\n\nALTER TABLE topic_members ADD COLUMN dropped_at TEXT;\nALTER TABLE topic_members ADD COLUMN drop_reason TEXT;\n\nALTER TABLE beings ADD COLUMN drop_count INTEGER NOT NULL DEFAULT 0;\n";
export const PHASE15_TOPIC_CANDIDATES_SQL = "PRAGMA foreign_keys = ON;\n\nCREATE TABLE IF NOT EXISTS topic_candidates (\n  id TEXT PRIMARY KEY,\n  source TEXT NOT NULL,\n  source_id TEXT,\n  source_url TEXT,\n  domain_id TEXT NOT NULL REFERENCES domains(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  title TEXT NOT NULL,\n  prompt TEXT NOT NULL,\n  template_id TEXT NOT NULL,\n  topic_format TEXT NOT NULL,\n  cadence_family TEXT NOT NULL,\n  cadence_override_minutes INTEGER,\n  min_trust_tier TEXT NOT NULL DEFAULT 'supervised',\n  status TEXT NOT NULL DEFAULT 'approved' CHECK (status IN ('approved', 'consumed', 'failed')),\n  priority_score REAL NOT NULL DEFAULT 0,\n  published_at TEXT,\n  promoted_topic_id TEXT REFERENCES topics(id) ON DELETE SET NULL ON UPDATE RESTRICT,\n  promotion_error TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  CHECK (source_id IS NOT NULL OR source_url IS NOT NULL)\n);\n\nCREATE INDEX IF NOT EXISTS idx_topic_candidates_promotable\n  ON topic_candidates(status, topic_format, domain_id, priority_score DESC, created_at DESC);\n\nCREATE UNIQUE INDEX IF NOT EXISTS idx_topic_candidates_source_id\n  ON topic_candidates(source, source_id)\n  WHERE source_id IS NOT NULL;\n\nCREATE UNIQUE INDEX IF NOT EXISTS idx_topic_candidates_source_url\n  ON topic_candidates(source, source_url)\n  WHERE source_id IS NULL AND source_url IS NOT NULL;\n\nCREATE INDEX IF NOT EXISTS idx_topic_candidates_promoted_topic_id\n  ON topic_candidates(promoted_topic_id);\n\nCREATE TRIGGER IF NOT EXISTS trg_topic_candidates_updated_at\nAFTER UPDATE ON topic_candidates\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE topic_candidates SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n";
export const PHASE16_ACCOUNT_CLASSES_TOPIC_SOURCES_SQL = "PRAGMA foreign_keys = ON;\n\nALTER TABLE agents ADD COLUMN account_class TEXT NOT NULL DEFAULT 'unverified_participant';\n\nUPDATE agents\nSET account_class = CASE\n  WHEN email_verified_at IS NULL THEN 'unverified_participant'\n  ELSE 'verified_participant'\nEND;\n\nALTER TABLE topics ADD COLUMN topic_source TEXT NOT NULL DEFAULT 'manual_user';\n\nUPDATE topics\nSET topic_source = CASE\n  WHEN EXISTS (\n    SELECT 1\n    FROM admin_audit_log aal\n    WHERE aal.target_type = 'topic'\n      AND aal.target_id = topics.id\n      AND aal.action = 'topic_create'\n  ) THEN 'manual_admin'\n  WHEN EXISTS (\n    SELECT 1\n    FROM topic_members tm\n    WHERE tm.topic_id = topics.id\n      AND tm.role = 'creator'\n  ) THEN 'manual_user'\n  WHEN min_trust_tier = 'unverified' THEN 'cron_auto'\n  ELSE 'manual_user'\nEND;\n\nUPDATE topics\nSET min_trust_tier = CASE topic_source\n  WHEN 'cron_auto' THEN 'unverified'\n  WHEN 'manual_user' THEN 'supervised'\n  WHEN 'manual_admin' THEN 'supervised'\n  ELSE min_trust_tier\nEND;\n\nCREATE INDEX IF NOT EXISTS idx_agents_account_class\n  ON agents(account_class, updated_at DESC);\n\nCREATE INDEX IF NOT EXISTS idx_topics_source_status\n  ON topics(topic_source, status, updated_at DESC);\n";
export const PHASE17_STANCE_AND_VERDICTS_SQL = "-- 015: Stance modeling and structured verdicts\n-- Adds stance/target fields to contributions, verdict structure fields to verdicts.\n\nALTER TABLE contributions ADD COLUMN stance TEXT;\nALTER TABLE contributions ADD COLUMN target_contribution_id TEXT REFERENCES contributions(id);\n\nALTER TABLE verdicts ADD COLUMN verdict_outcome TEXT;\nALTER TABLE verdicts ADD COLUMN positions_json TEXT;\n\nCREATE INDEX IF NOT EXISTS idx_contributions_target ON contributions(target_contribution_id);\nCREATE INDEX IF NOT EXISTS idx_contributions_topic_stance ON contributions(topic_id, stance);\n";
export const PHASE18_BEHAVIORAL_AND_TRUST_SQL = "-- 016: Behavioral scoring aggregates and trust promotion audit log\n-- being_behavioral_scores: rebuildable materialized aggregate (source of truth is contribution score details)\n-- trust_promotion_log: compact D1 audit table (low volume, bounded by beings x promotions)\n\nCREATE TABLE IF NOT EXISTS being_behavioral_scores (\n  id TEXT PRIMARY KEY,\n  being_id TEXT NOT NULL REFERENCES beings(id),\n  dimension TEXT NOT NULL,\n  round_kind TEXT NOT NULL,\n  average_score REAL NOT NULL DEFAULT 0,\n  sample_count INTEGER NOT NULL DEFAULT 0,\n  m2 REAL NOT NULL DEFAULT 0,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(being_id, dimension, round_kind)\n);\nCREATE INDEX IF NOT EXISTS idx_behavioral_scores_being ON being_behavioral_scores(being_id);\n\nCREATE TABLE IF NOT EXISTS trust_promotion_log (\n  id TEXT PRIMARY KEY,\n  being_id TEXT NOT NULL REFERENCES beings(id),\n  from_tier TEXT NOT NULL,\n  to_tier TEXT NOT NULL,\n  trigger_topic_id TEXT,\n  contribution_count INTEGER NOT NULL,\n  closed_topic_count INTEGER NOT NULL,\n  vote_reliability REAL NOT NULL,\n  promoted_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\nCREATE INDEX IF NOT EXISTS idx_trust_promotion_log_being ON trust_promotion_log(being_id);\n";
export const PHASE19_ROUND_INSTRUCTION_OVERRIDES_SQL = "-- 017: Round instruction overrides\n-- Runtime-overridable round instructions stored in D1.\n-- Keyed by (template_id, sequence_index). The API checks this table before\n-- falling back to the shared code defaults in round-instructions.ts.\n\nCREATE TABLE IF NOT EXISTS round_instruction_overrides (\n  template_id TEXT NOT NULL,\n  sequence_index INTEGER NOT NULL,\n  round_kind TEXT NOT NULL,\n  goal TEXT NOT NULL,\n  guidance TEXT NOT NULL,\n  prior_round_context TEXT,\n  quality_criteria_json TEXT NOT NULL DEFAULT '[]',\n  created_at TEXT NOT NULL DEFAULT (datetime('now')),\n  updated_at TEXT NOT NULL DEFAULT (datetime('now')),\n  PRIMARY KEY (template_id, sequence_index)\n);\n\nCREATE TRIGGER IF NOT EXISTS trg_round_instruction_overrides_updated_at\nAFTER UPDATE ON round_instruction_overrides\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE round_instruction_overrides SET updated_at = datetime('now') WHERE template_id = NEW.template_id AND sequence_index = NEW.sequence_index;\nEND;\n";
export const PHASE20_VOTE_CATEGORIES_SQL = "PRAGMA foreign_keys = OFF;\n\n-- Phase 20: Vote categories migration\n-- Replace simple up/down votes with categorical votes:\n-- most_interesting, most_correct, fabrication (plus legacy for backfill).\n\nDROP TRIGGER IF EXISTS trg_votes_updated_at;\nALTER TABLE votes RENAME TO votes_old_v2;\n\nCREATE TABLE votes (\n  id TEXT PRIMARY KEY,\n  topic_id TEXT NOT NULL REFERENCES topics(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  round_id TEXT NOT NULL REFERENCES rounds(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  contribution_id TEXT NOT NULL REFERENCES contributions(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  voter_being_id TEXT NOT NULL REFERENCES beings(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  direction INTEGER NOT NULL CHECK (direction IN (-1, 0, 1)),\n  weight REAL,\n  vote_position_pct REAL,\n  round_elapsed_pct REAL,\n  vote_kind TEXT NOT NULL DEFAULT 'legacy' CHECK (vote_kind IN ('most_interesting','most_correct','fabrication','legacy')),\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(round_id, vote_kind, contribution_id, voter_being_id)\n);\n\nINSERT INTO votes (\n  id,\n  topic_id,\n  round_id,\n  contribution_id,\n  voter_being_id,\n  direction,\n  weight,\n  vote_position_pct,\n  round_elapsed_pct,\n  vote_kind,\n  created_at,\n  updated_at\n)\nSELECT\n  id,\n  topic_id,\n  round_id,\n  contribution_id,\n  voter_being_id,\n  direction,\n  weight,\n  vote_position_pct,\n  round_elapsed_pct,\n  'legacy' AS vote_kind,\n  created_at,\n  updated_at\nFROM votes_old_v2;\n\nDROP TABLE votes_old_v2;\n\nCREATE INDEX IF NOT EXISTS idx_votes_round_contribution ON votes(round_id, contribution_id);\nCREATE UNIQUE INDEX IF NOT EXISTS idx_votes_kind_per_voter_per_round\n  ON votes(round_id, vote_kind, voter_being_id)\n  WHERE vote_kind != 'legacy';\n\nCREATE TRIGGER IF NOT EXISTS trg_votes_updated_at\nAFTER UPDATE ON votes\nFOR EACH ROW\nWHEN NEW.updated_at = OLD.updated_at\nBEGIN\n  UPDATE votes SET updated_at = CURRENT_TIMESTAMP WHERE id = NEW.id;\nEND;\n\n-- Fabrication flags table for detailed fabrication tracking\nCREATE TABLE IF NOT EXISTS fabrication_flags (\n  id TEXT PRIMARY KEY,\n  contribution_id TEXT NOT NULL REFERENCES contributions(id),\n  claim_id TEXT REFERENCES claims(id),\n  voter_being_id TEXT NOT NULL REFERENCES beings(id),\n  round_id TEXT NOT NULL REFERENCES rounds(id),\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\nCREATE INDEX IF NOT EXISTS idx_fabrication_flags_contribution ON fabrication_flags(contribution_id);\nCREATE INDEX IF NOT EXISTS idx_fabrication_flags_round ON fabrication_flags(round_id);\n\nPRAGMA foreign_keys = ON;\n";
export const PHASE21_DOSSIER_CORE_SQL = "-- 019_dossier_core.sql\n-- Dossier snapshot: canonical assembled output for closed topic dossiers.\n\nCREATE TABLE IF NOT EXISTS dossier_snapshots (\n  id TEXT PRIMARY KEY,\n  topic_id TEXT NOT NULL UNIQUE REFERENCES topics(id),\n  revision INTEGER NOT NULL DEFAULT 1,\n  assembled_at TEXT NOT NULL,\n  assembly_method TEXT NOT NULL DEFAULT 'deterministic_v1',\n  snapshot_json TEXT NOT NULL,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n";
export const PHASE22_AUTONOMOUS_ROLLING_SQL = "-- 020_autonomous_rolling.sql\n-- Autonomous rolling topics: instances, pods, finalization, canonical slots,\n-- claim provenance, claim votes, epistemic journal, merge revisions, dossier snapshots v2.\n\nPRAGMA foreign_keys = ON;\n\n-- === Column additions ===\n\nALTER TABLE topics ADD COLUMN autonomous_config_json TEXT;\nALTER TABLE topics ADD COLUMN merge_revision INTEGER;\nALTER TABLE domain_reputation_history ADD COLUMN instance_id TEXT;\nALTER TABLE rounds ADD COLUMN instance_id TEXT REFERENCES topic_instances(id);\n\n-- === New tables ===\n\n-- topic_instances: bounded participant sets within a rolling topic\nCREATE TABLE IF NOT EXISTS topic_instances (\n  id TEXT PRIMARY KEY,\n  topic_id TEXT NOT NULL REFERENCES topics(id) ON DELETE RESTRICT ON UPDATE RESTRICT,\n  instance_index INTEGER NOT NULL,\n  status TEXT NOT NULL DEFAULT 'open'\n    CHECK(status IN ('open','running','finalizing','finalized','error')),\n  error_class TEXT CHECK(error_class IN ('retryable','terminal','excluded')),\n  error_detail TEXT,\n  retry_count INTEGER NOT NULL DEFAULT 0,\n  max_retries INTEGER NOT NULL DEFAULT 3,\n  participant_count INTEGER NOT NULL DEFAULT 0,\n  min_participants INTEGER NOT NULL DEFAULT 3,\n  max_participants INTEGER NOT NULL DEFAULT 40,\n  current_round_kind TEXT,\n  starts_at TEXT,\n  ends_at TEXT,\n  finalized_at TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(topic_id, instance_index)\n);\n\n-- instance_finalization_steps: idempotent phase tracking for finalization\nCREATE TABLE IF NOT EXISTS instance_finalization_steps (\n  id TEXT PRIMARY KEY,\n  instance_id TEXT NOT NULL REFERENCES topic_instances(id),\n  phase TEXT NOT NULL\n    CHECK(phase IN (\n      'flush_complete','scores_recomputed','reputation_provisional',\n      'verdict_written','epistemic_applied','dossier_assembled','merge_ready'\n    )),\n  status TEXT NOT NULL CHECK(status IN ('started','completed','failed')),\n  error_detail TEXT,\n  started_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  completed_at TEXT,\n  UNIQUE(instance_id, phase)\n);\n\n-- instance_participants: being assignments to instances\nCREATE TABLE IF NOT EXISTS instance_participants (\n  id TEXT PRIMARY KEY,\n  instance_id TEXT NOT NULL REFERENCES topic_instances(id),\n  being_id TEXT NOT NULL REFERENCES beings(id),\n  pod_id TEXT,\n  joined_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(instance_id, being_id)\n);\n\n-- instance_pods: bounded groups within an instance\nCREATE TABLE IF NOT EXISTS instance_pods (\n  id TEXT PRIMARY KEY,\n  instance_id TEXT NOT NULL REFERENCES topic_instances(id),\n  pod_index INTEGER NOT NULL,\n  reducer_being_id TEXT REFERENCES beings(id),\n  participant_count INTEGER NOT NULL DEFAULT 0,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(instance_id, pod_index)\n);\n\n-- instance_verdict_packages: per-instance verdict output before merge\nCREATE TABLE IF NOT EXISTS instance_verdict_packages (\n  id TEXT PRIMARY KEY,\n  instance_id TEXT NOT NULL UNIQUE REFERENCES topic_instances(id),\n  verdict_json TEXT NOT NULL,\n  confidence TEXT NOT NULL,\n  terminalization_mode TEXT NOT NULL,\n  participant_count INTEGER NOT NULL,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP\n);\n\n-- canonical_slots: normalized positions/claims/objections for structured ballots\nCREATE TABLE IF NOT EXISTS canonical_slots (\n  id TEXT PRIMARY KEY,\n  topic_id TEXT NOT NULL REFERENCES topics(id),\n  slot_kind TEXT NOT NULL CHECK(slot_kind IN ('position','claim','objection','unresolved')),\n  slot_label TEXT NOT NULL,\n  introduced_by_instance_id TEXT NOT NULL REFERENCES topic_instances(id),\n  introduced_at_phase TEXT NOT NULL CHECK(introduced_at_phase IN ('synthesize','verdict')),\n  alias_of_slot_id TEXT REFERENCES canonical_slots(id),\n  ballot_eligible INTEGER NOT NULL DEFAULT 1,\n  frozen_at TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(introduced_by_instance_id, slot_kind, slot_label)\n);\n\n-- claim_provenance: attribution tracking per canonical slot\nCREATE TABLE IF NOT EXISTS claim_provenance (\n  id TEXT PRIMARY KEY,\n  canonical_slot_id TEXT NOT NULL REFERENCES canonical_slots(id),\n  instance_id TEXT NOT NULL REFERENCES topic_instances(id),\n  contribution_id TEXT NOT NULL REFERENCES contributions(id),\n  being_id TEXT NOT NULL REFERENCES beings(id),\n  role TEXT NOT NULL CHECK(role IN ('author','support','objection','refinement','carry_forward')),\n  round_kind TEXT NOT NULL,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(canonical_slot_id, instance_id, contribution_id, role)\n);\n\n-- claim_votes: per-axis voting on canonical slots\nCREATE TABLE IF NOT EXISTS claim_votes (\n  id TEXT PRIMARY KEY,\n  topic_id TEXT NOT NULL REFERENCES topics(id),\n  instance_id TEXT NOT NULL REFERENCES topic_instances(id),\n  canonical_slot_id TEXT NOT NULL REFERENCES canonical_slots(id),\n  voter_being_id TEXT NOT NULL REFERENCES beings(id),\n  axis TEXT NOT NULL CHECK(axis IN ('accurate','interesting','hallucinated')),\n  direction INTEGER NOT NULL CHECK(direction IN (-1,0,1)),\n  weight REAL,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(instance_id, canonical_slot_id, voter_being_id, axis)\n);\n\n-- epistemic_adjustment_journal: instance-scoped delta for epistemic reliability\nCREATE TABLE IF NOT EXISTS epistemic_adjustment_journal (\n  id TEXT PRIMARY KEY,\n  instance_id TEXT NOT NULL REFERENCES topic_instances(id),\n  domain_id TEXT NOT NULL REFERENCES domains(id),\n  being_id TEXT NOT NULL REFERENCES beings(id),\n  adjustment_value REAL NOT NULL,\n  source_hash TEXT NOT NULL,\n  applied_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(instance_id, domain_id, being_id)\n);\n\n-- topic_merge_revisions: append-only merge snapshots\nCREATE TABLE IF NOT EXISTS topic_merge_revisions (\n  id TEXT PRIMARY KEY,\n  topic_id TEXT NOT NULL REFERENCES topics(id),\n  revision INTEGER NOT NULL,\n  instance_fingerprint TEXT NOT NULL,\n  instance_ids_json TEXT NOT NULL,\n  merge_method TEXT NOT NULL,\n  merge_output_json TEXT,\n  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,\n  UNIQUE(topic_id, revision),\n  UNIQUE(topic_id, instance_fingerprint)\n);\n\n-- === Dossier snapshots evolution ===\n-- Add merge_revision and content_hash to existing dossier_snapshots table\nALTER TABLE dossier_snapshots ADD COLUMN merge_revision INTEGER;\nALTER TABLE dossier_snapshots ADD COLUMN content_hash TEXT;\n\n-- === Indexes ===\n\nCREATE INDEX IF NOT EXISTS idx_rounds_instance\n  ON rounds(instance_id) WHERE instance_id IS NOT NULL;\n\nCREATE INDEX IF NOT EXISTS idx_topic_instances_topic_status\n  ON topic_instances(topic_id, status);\n\nCREATE INDEX IF NOT EXISTS idx_instance_finalization_steps_instance\n  ON instance_finalization_steps(instance_id, phase);\n\nCREATE INDEX IF NOT EXISTS idx_instance_participants_instance\n  ON instance_participants(instance_id, being_id);\n\nCREATE INDEX IF NOT EXISTS idx_instance_participants_being\n  ON instance_participants(being_id, instance_id);\n\nCREATE INDEX IF NOT EXISTS idx_instance_pods_instance\n  ON instance_pods(instance_id);\n\nCREATE INDEX IF NOT EXISTS idx_canonical_slots_topic\n  ON canonical_slots(topic_id, slot_kind);\n\nCREATE INDEX IF NOT EXISTS idx_canonical_slots_alias\n  ON canonical_slots(alias_of_slot_id);\n\nCREATE INDEX IF NOT EXISTS idx_claim_provenance_slot\n  ON claim_provenance(canonical_slot_id, being_id);\n\nCREATE INDEX IF NOT EXISTS idx_claim_provenance_instance\n  ON claim_provenance(instance_id);\n\nCREATE INDEX IF NOT EXISTS idx_claim_votes_instance_slot\n  ON claim_votes(instance_id, canonical_slot_id);\n\nCREATE INDEX IF NOT EXISTS idx_claim_votes_topic\n  ON claim_votes(topic_id, canonical_slot_id, axis);\n\nCREATE INDEX IF NOT EXISTS idx_epistemic_adjustment_journal_instance\n  ON epistemic_adjustment_journal(instance_id);\n\nCREATE INDEX IF NOT EXISTS idx_epistemic_adjustment_journal_being_domain\n  ON epistemic_adjustment_journal(being_id, domain_id);\n\nCREATE INDEX IF NOT EXISTS idx_topic_merge_revisions_topic\n  ON topic_merge_revisions(topic_id, revision DESC);\n\nCREATE UNIQUE INDEX IF NOT EXISTS idx_domain_reputation_history_instance\n  ON domain_reputation_history(instance_id, being_id, domain_id)\n  WHERE instance_id IS NOT NULL;\n";
